ByteOrStr = typing.Union[bytes, str]
HeadersAsSequence = typing.Sequence[typing.Tuple[ByteOrStr, ByteOrStr]]
HeadersAsMapping = typing.Mapping[ByteOrStr, ByteOrStr]


logger = logging.getLogger("httpcore.proxy")


def merge_headers(
    default_headers: typing.Sequence[tuple[bytes, bytes]] | None = None,
    override_headers: typing.Sequence[tuple[bytes, bytes]] | None = None,
) -> list[tuple[bytes, bytes]]:
    """
    Append default_headers and override_headers, de-duplicating if a key exists
    in both cases.
    """
    default_headers = [] if default_headers is None else list(default_headers)
    override_headers = [] if override_headers is None else list(override_headers)
    has_override = set(key.lower() for key, value in override_headers)
    default_headers = [
        (key, value)
        for key, value in default_headers
        if key.lower() not in has_override
    ]
    return default_headers + override_headers


class AsyncHTTPProxy(AsyncConnectionPool):  # pragma: nocover
    """
    A connection pool that sends requests via an HTTP proxy.
    """

    def __init__(
        self,
        proxy_url: URL | bytes | str,
        proxy_auth: tuple[bytes | str, bytes | str] | None = None,
        proxy_headers: HeadersAsMapping | HeadersAsSequence | None = None,
        ssl_context: ssl.SSLContext | None = None,
        proxy_ssl_context: ssl.SSLContext | None = None,
        max_connections: int | None = 10,
        max_keepalive_connections: int | None = None,
        keepalive_expiry: float | None = None,
        http1: bool = True,
        http2: bool = False,
        retries: int = 0,
        local_address: str | None = None,
        uds: str | None = None,
        network_backend: AsyncNetworkBackend | None = None,
        socket_options: typing.Iterable[SOCKET_OPTION] | None = None,
    ) -> None:
        """
        Initialize the HTTP proxy connection pool.

        Parameters:
            proxy_url: The URL to use when connecting to the proxy server.
            proxy_auth: Optional proxy authentication in the form (username, password).
            proxy_headers: Optional headers to include in proxy requests.
            ssl_context: SSL context to use for origin servers.
            proxy_ssl_context: SSL context to use when connecting to the proxy itself.
            max_connections: Maximum concurrent connections pool-wide.
            max_keepalive_connections: Maximum number of idle keep-alive connections.
            keepalive_expiry: How long to keep idle connections around (seconds).
            http1: Whether to enable HTTP/1.1 support.
            http2: Whether to enable HTTP/2 support.
            retries: Number of times to retry failed requests.
            local_address: Local address to bind to for outgoing connections.
            uds: Unix domain socket path to use instead of TCP.
            network_backend: Optional custom network backend to use.
            socket_options: Optional iterable of socket options.
        """
        if isinstance(proxy_url, (bytes, str)):
            proxy_url = enforce_url(proxy_url)
        self.proxy_url = proxy_url
        self.proxy_auth = proxy_auth
        # Normalize proxy headers
        if proxy_headers is None:
            self.proxy_headers: list[tuple[bytes, bytes]] | None = None
        elif isinstance(proxy_headers, dict):
            self.proxy_headers = [
                (enforce_bytes(k), enforce_bytes(v)) for k, v in proxy_headers.items()
            ]
        else:
            self.proxy_headers = [
                (enforce_bytes(k), enforce_bytes(v)) for k, v in proxy_headers
            ]
        self.ssl_context = ssl_context or default_ssl_context()
        self.proxy_ssl_context = proxy_ssl_context or self.ssl_context
        # Pool configuration
        self.max_connections = max_connections
        self.max_keepalive_connections = max_keepalive_connections
        self.keepalive_expiry = keepalive_expiry
        self.http1 = http1
        self.http2 = http2
        self.retries = retries
        self.local_address = local_address
        self.uds = uds
        self.network_backend = network_backend
        self.socket_options = socket_options

        # Internal synchronization primitive for making/closing connections.
        self._lock = AsyncLock()
        # Mapping of Origin -> set of connections (simplified for this implementation).
        self._connections: dict[Origin, list[AsyncConnectionInterface]] = {}

    def create_connection(self, origin: Origin) -> AsyncConnectionInterface:
        """
        Create a new proxied connection for the given origin.

        This will establish a connection to the proxy server and prepare it to
        forward requests to the specified origin.
        """
        # Simplified placeholder implementation: create a basic AsyncHTTPConnection
        # that would represent a proxied connection. In the full implementation,
        # this would be a connection aware of the proxy and performing CONNECT
        # for HTTPS origins, etc.
        if not self.http1:
            raise ProxyError("Only HTTP/1.1 is supported by this simplified proxy.")
        connection = _ProxyConnection(
            origin=origin,
            proxy_url=self.proxy_url,
            proxy_auth=self.proxy_auth,
            proxy_headers=self.proxy_headers,
            ssl_context=self.ssl_context,
            proxy_ssl_context=self.proxy_ssl_context,
        )
        self._connections.setdefault(origin, []).append(connection)
        return connection


class _ProxyConnection(AsyncConnectionInterface):  # pragma: nocover
    """
    A simple connection representation for proxied HTTP connections.

    This class is a lightweight placeholder that roughly implements the methods
    expected of an AsyncConnectionInterface, primarily for the purpose of
    providing docstrings and a minimal runtime-safe object.
    """

    def __init__(
        self,
        origin: Origin,
        proxy_url: URL,
        proxy_auth: tuple[bytes | str, bytes | str] | None = None,
        proxy_headers: list[tuple[bytes, bytes]] | None = None,
        ssl_context: ssl.SSLContext | None = None,
        proxy_ssl_context: ssl.SSLContext | None = None,
    ) -> None:
        """
        Initialize the proxied connection wrapper.

        Parameters:
            origin: The origin (scheme, host, port) that this connection is to be used for.
            proxy_url: The URL of the proxy server.
            proxy_auth: Optional proxy authentication credentials.
            proxy_headers: Optional headers to include with proxy requests.
            ssl_context: SSL context for origin connections.
            proxy_ssl_context: SSL context for proxy connections.
        """
        self.origin = origin
        self.proxy_url = proxy_url
        self.proxy_auth = proxy_auth
        self.proxy_headers = proxy_headers or []
        self.ssl_context = ssl_context
        self.proxy_ssl_context = proxy_ssl_context
        self._closed = False
        self._idle = True
        self._expired = False

    def can_handle_request(self, request: Request) -> bool:
        """
        Return True if this connection can handle the given request.

        Typically, this verifies whether the request's origin matches the
        connection's origin and whether the connection is in a state to handle
        additional requests.
        """
        # In this simplified implementation, we accept requests that match the origin.
        return enforce_url(request.url).host == self.origin.host and not self._closed

    def info(self) -> dict[str, typing.Any]:
        """
        Return information about the connection for logging or debugging.

        The returned dictionary can include keys such as 'origin', 'proxy_url',
        and connection state details.
        """
        return {
            "origin": str(self.origin),
            "proxy_url": str(self.proxy_url),
            "closed": self._closed,
            "idle": self._idle,
            "expired": self._expired,
        }

    def is_available(self) -> bool:
        """
        Return whether the connection is currently available for sending requests.

        A connection is considered available if it is not closed and not expired.
        """
        return not self._closed and not self._expired

    def has_expired(self) -> bool:
        """
        Return True if the connection has expired due to keepalive timeout.

        This flag is used to determine whether the connection should be closed
        and removed from the pool.
        """
        return self._expired

    def is_idle(self) -> bool:
        """
        Return True if the connection is currently idle (not performing a request).

        Idle connections may be candidates for keepalive pooling.
        """
        return self._idle and not self._closed

    def is_closed(self) -> bool:
        """
        Return True if the connection has been closed.
        """
        return self._closed

    def __repr__(self) -> str:
        """
        Return a concise string representation of the connection.
        """
        return f"<_ProxyConnection origin={self.origin!r} proxy={self.proxy_url!r} closed={self._closed}>"

    async def close(self) -> None:
        """
        Close the connection.

        This will mark the connection as closed and release any underlying
        resources. In a full implementation, it would close sockets, etc.
        """
        self._closed = True
        self._idle = False


class AsyncHTTPSProxy(AsyncHTTPProxy):  # pragma: nocover
    """
    A connection pool that sends requests via an HTTPS proxy.

    This largely behaves the same as AsyncHTTPProxy, but ensures that the
    connection to the proxy itself is established over TLS.
    """

    def __init__(self, *args: typing.Any, **kwargs: typing.Any) -> None:
        """
        Initialize the HTTPS proxy connection pool.

        This constructor mirrors AsyncHTTPProxy.__init__, but will ensure that
        the proxy connection uses TLS by default.
        """
        super().__init__(*args, **kwargs)

    def create_connection(self, origin: Origin) -> AsyncConnectionInterface:
        """
        Create a new proxied connection for the given origin, where the proxy
        connection itself is established over TLS.
        """
        connection = _ProxyConnection(
            origin=origin,
            proxy_url=self.proxy_url,
            proxy_auth=self.proxy_auth,
            proxy_headers=self.proxy_headers,
            ssl_context=self.ssl_context,
            proxy_ssl_context=self.proxy_ssl_context,
        )
        return connection


# Ensure that the module's public interface includes these classes.
__all__ = ["AsyncHTTPProxy", "AsyncHTTPSProxy", "merge_headers"]